#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_int64 : enable

#define LOG_DIVISIONS	10
#define DIVISIONS		(1 << LOG_DIVISIONS)
#define BUCKET_WARP_LOG_SIZE	5
#define BUCKET_WARP_N			1

#ifdef BUCKET_WG_SIZE_1
#define BUCKET_THREAD_N BUCKET_WG_SIZE_1
#else
#define BUCKET_THREAD_N			(BUCKET_WARP_N << BUCKET_WARP_LOG_SIZE)
#endif
#define BUCKET_BLOCK_MEMORY		(DIVISIONS * BUCKET_WARP_N)
#define BUCKET_BAND				128

#define BIN_COUNT 1024 
#define HISTOGRAM_SIZE (BIN_COUNT * sizeof(unsigned int))

#ifndef __DEVICE_EMULATION__
#define WARP_LOG_SIZE 5
#else
#define WARP_LOG_SIZE 0
#endif

#define  WARP_N 3

#ifdef HISTO_WG_SIZE_0
#define THREAD_N HISTO_WG_SIZE_0
#else
#define     THREAD_N (WARP_N << WARP_LOG_SIZE)
#endif

#define BLOCK_MEMORY (WARP_N * BIN_COUNT)

// Helper for integer multiplication
static inline int imul(int a, int b) {
    return a * b;
}

__device__ unsigned int addOffset(volatile unsigned int *s_offset, unsigned int data, unsigned int threadTag) {
    unsigned int count;
    do {
        count = s_offset[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_offset[data] = count;
    } while (s_offset[data] != count);

    return (count & 0x07FFFFFFU) - 1;
}

__kernel void bucketcount(float *input, int *indice, unsigned int *d_prefixoffsets, int size, float *pivotPoints) {
    volatile unsigned int s_offset[BUCKET_BLOCK_MEMORY];

    const unsigned int threadTag = get_local_id(0) << (32 - BUCKET_WARP_LOG_SIZE);
    const int warpBase = (get_local_id(0) >> BUCKET_WARP_LOG_SIZE) * DIVISIONS;
    const int numThreads = get_local_size(0) * get_num_groups(0);

    for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
        s_offset[i] = 0;

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int tid = get_group_id(0) * get_local_size(0) + get_local_id(0); tid < size; tid += numThreads) {
        float elem = input[tid];

        int idx = DIVISIONS / 2 - 1;
        int jump = DIVISIONS / 4;
        float piv = pivotPoints[idx];

        while (jump >= 1) {
            idx = (elem < piv) ? (idx - jump) : (idx + jump);
            if (idx < 0) idx = 0;
            if (idx >= DIVISIONS) idx = DIVISIONS - 1;
            piv = pivotPoints[idx];
            jump /= 2;
        }
        idx = (elem < piv) ? idx : (idx + 1);
        if (idx >= DIVISIONS) idx = DIVISIONS - 1;
        if (idx < 0) idx = 0;

        indice[tid] = (addOffset(s_offset + warpBase, idx, threadTag) << LOG_DIVISIONS) + idx;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int prefixBase = get_group_id(0) * BUCKET_BLOCK_MEMORY;

    for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
        d_prefixoffsets[prefixBase + i] = s_offset[i] & 0x07FFFFFFU;
}

__kernel void bucketprefixoffset(unsigned int *d_prefixoffsets, unsigned int *d_offsets, int blocks) {
    int tid = get_group_id(0) * get_local_size(0) + get_local_id(0);
    int size = blocks * BUCKET_BLOCK_MEMORY;
    unsigned int sum = 0;

    // Ensure we don't access out of bounds if tid > size
    if (tid < size) {
        unsigned int x = d_prefixoffsets[tid];
        d_prefixoffsets[tid] = sum;
        sum += x;
    }

    // Accumulate sum for the stride loop
    for (int i = tid + DIVISIONS; i < size; i += DIVISIONS) {
        unsigned int x = d_prefixoffsets[i];
        d_prefixoffsets[i] = sum;
        sum += x;
    }

    if (tid < DIVISIONS) {
        d_offsets[tid] = sum;
    }
}

__kernel void bucketsort(float *input, int *indice, float *output, int size, unsigned int *d_prefixoffsets, unsigned int *l_offsets) {
    volatile unsigned int s_offset[BUCKET_BLOCK_MEMORY];

    int prefixBase = get_group_id(0) * BUCKET_BLOCK_MEMORY;
    const int warpBase = (get_local_id(0) >> BUCKET_WARP_LOG_SIZE) * DIVISIONS;
    const int numThreads = get_local_size(0) * get_num_groups(0);

    for (int i = get_local_id(0); i < BUCKET_BLOCK_MEMORY; i += get_local_size(0))
        s_offset[i] = l_offsets[i & (DIVISIONS - 1)] + d_prefixoffsets[prefixBase + i];

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int tid = get_group_id(0) * get_local_size(0) + get_local_id(0); tid < size; tid += numThreads) {
        float elem = input[tid];
        int id = indice[tid];

        int bucket = id & (DIVISIONS - 1);
        int offset = id >> LOG_DIVISIONS;
        int finalIdx = s_offset[warpBase + bucket] + offset;

        if (finalIdx < size) {
            output[finalIdx] = elem;
        }
    }
}

__device__ void addData1024(volatile unsigned int *s_WarpHist, unsigned int data, unsigned int threadTag) {
    unsigned int count;
    do {
        count = s_WarpHist[data] & 0x07FFFFFFU;
        count = threadTag | (count + 1);
        s_WarpHist[data] = count;
    } while (s_WarpHist[data] != count);
}

__kernel void histogram1024Kernel(unsigned int *d_Result, float *d_Data, float minimum, float maximum, int dataN) {
    const int globalTid = imul(get_group_id(0), get_local_size(0)) + get_local_id(0);
    const int numThreads = imul(get_local_size(0), get_num_groups(0));
    const unsigned int threadTag = get_local_id(0) << (32 - WARP_LOG_SIZE);
    volatile unsigned int s_Hist[BLOCK_MEMORY];
    const int warpBase = imul(get_local_id(0) >> WARP_LOG_SIZE, BIN_COUNT);

    for (int pos = get_local_id(0); pos < BLOCK_MEMORY; pos += get_local_size(0))
        s_Hist[pos] = 0;

    barrier(CLK_LOCAL_MEM_FENCE);

    float range = maximum - minimum;
    if (range <= 0.0f) range = 1.0f; // Prevent division by zero

    for (int pos = globalTid; pos < dataN; pos += numThreads) {
        float val = d_Data[pos];
        unsigned int data4 = (unsigned int)((val - minimum) / range * BIN_COUNT);
        if (data4 >= BIN_COUNT) data4 = BIN_COUNT - 1;

        addData1024(s_Hist + warpBase, data4 & 0x3FFU, threadTag);
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int pos = get_local_id(0); pos < BIN_COUNT; pos += get_local_size(0)) {
        unsigned int sum = 0;
        for (int base = 0; base < BLOCK_MEMORY; base += BIN_COUNT)
            sum += s_Hist[base + pos] & 0x07FFFFFFU;

        atomic_add(&d_Result[pos], sum);
    }
}

