#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_int64 : enable

#define LOG_DIVISIONS	10
#define DIVISIONS		(1 << LOG_DIVISIONS)
#define BUCKET_WARP_LOG_SIZE	5
#define BUCKET_WARP_N			1

#ifdef BUCKET_WG_SIZE_1
#define BUCKET_THREAD_N BUCKET_WG_SIZE_1
#else
#define BUCKET_THREAD_N			(BUCKET_WARP_N << BUCKET_WARP_LOG_SIZE)
#endif
#define BUCKET_BLOCK_MEMORY		(DIVISIONS * BUCKET_WARP_N)
#define BUCKET_BAND				128

#define BLOCKSIZE	256
#define ROW_LENGTH	(BLOCKSIZE * 4)
#define ROWS		4096

__device__ float4 sortElem(float4 r) {
    float4 nr;

    nr.x = (r.x > r.y) ? r.y : r.x;
    nr.y = (r.y > r.x) ? r.y : r.x;
    nr.z = (r.z > r.w) ? r.w : r.z;
    nr.w = (r.w > r.z) ? r.w : r.z;

    r.x = (nr.x > nr.z) ? nr.z : nr.x;
    r.y = (nr.w < nr.y) ? nr.w : nr.y;
    r.z = (nr.x < nr.z) ? nr.z : nr.x;
    r.w = (nr.y < nr.w) ? nr.w : nr.y;

    nr.x = r.x;
    nr.y = (r.y > r.z) ? r.z : r.y;
    nr.z = (r.z > r.y) ? r.z : r.y;
    nr.w = r.w;
    return nr;
}

__device__ float4 getLowest(float4 a, float4 b) {
    a.x = (a.x < b.w) ? a.x : b.w;
    a.y = (a.y < b.z) ? a.y : b.z;
    a.z = (a.z < b.y) ? a.z : b.y;
    a.w = (a.w < b.x) ? a.w : b.x;
    return a;
}

__device__ float4 getHighest(float4 a, float4 b) {
    b.x = (a.w >= b.x) ? a.w : b.x;
    b.y = (a.z >= b.y) ? a.z : b.y;
    b.z = (a.y >= b.z) ? a.y : b.z;
    b.w = (a.x >= b.w) ? a.x : b.w;
    return b;
}

__kernel void mergeSortFirst(float4 *result, int listsize, float *texData, int *constStartAddr) {
    int bx = get_group_id(0);
    int idx = bx * get_local_size(0) + get_local_id(0);

    if (idx < listsize / 4) {
        float4 r;
        r.x = texData[idx * 4];
        r.y = texData[idx * 4 + 1];
        r.z = texData[idx * 4 + 2];
        r.w = texData[idx * 4 + 3];
        result[idx] = sortElem(r);
    }
}

__kernel void mergeSortPass(float4 *result, int nrElems, int threadsPerDiv, float *texData, int *constStartAddr, int *finalStartAddr, int *nullElems) {
    int tid = get_group_id(0) * get_local_size(0) + get_local_id(0);

    int division = tid / threadsPerDiv;
    if (division >= DIVISIONS) return;

    int int_tid = tid - division * threadsPerDiv;
    int Astart = constStartAddr[division] + int_tid * nrElems;
    int Bstart = Astart + nrElems / 2;

    // Check bounds before accessing
    if (Astart >= constStartAddr[division + 1])
        return;

    float4 *resStart = &(result[Astart]);

    if (constStartAddr[division + 1] <= Bstart) {
        int count = constStartAddr[division + 1] - Astart;
        for (int i = 0; i < count; i++) {
            int idx = Astart + i;
            float4 val;
            val.x = texData[idx * 4];
            val.y = texData[idx * 4 + 1];
            val.z = texData[idx * 4 + 2];
            val.w = texData[idx * 4 + 3];
            resStart[i] = val;
        }
        return;
    }

    int aidx = 0;
    int bidx = 0;
    int outidx = 0;
    float4 a, b;

    int idxA = Astart + aidx;
    a.x = texData[idxA * 4];
    a.y = texData[idxA * 4 + 1];
    a.z = texData[idxA * 4 + 2];
    a.w = texData[idxA * 4 + 3];

    int idxB = Bstart + bidx;
    b.x = texData[idxB * 4];
    b.y = texData[idxB * 4 + 1];
    b.z = texData[idxB * 4 + 2];
    b.w = texData[idxB * 4 + 3];

    int limitA = nrElems / 2;
    int limitB = constStartAddr[division + 1] - Bstart;
    if (limitB > nrElems / 2) limitB = nrElems / 2;

    while (true) {
        float4 nextA, nextB;
        bool hasNextA = (aidx + 1 < limitA);
        bool hasNextB = (bidx + 1 < limitB);

        if (hasNextA) {
            int nextIdxA = Astart + aidx + 1;
            nextA.x = texData[nextIdxA * 4];
            nextA.y = texData[nextIdxA * 4 + 1];
            nextA.z = texData[nextIdxA * 4 + 2];
            nextA.w = texData[nextIdxA * 4 + 3];
        }

        if (hasNextB) {
            int nextIdxB = Bstart + bidx + 1;
            nextB.x = texData[nextIdxB * 4];
            nextB.y = texData[nextIdxB * 4 + 1];
            nextB.z = texData[nextIdxB * 4 + 2];
            nextB.w = texData[nextIdxB * 4 + 3];
        }

        float4 na = getLowest(a, b);
        float4 nb = getHighest(a, b);
        a = sortElem(na);
        b = sortElem(nb);

        resStart[outidx++] = a;

        if (hasNextA) {
            if (hasNextB) {
                if (nextB.x > nextA.x) {
                    aidx += 1;
                    a = nextA;
                } else {
                    bidx += 1;
                    a = nextB;
                }
            } else {
                aidx += 1;
                a = nextA;
            }
        } else {
            if (hasNextB) {
                bidx += 1;
                a = nextB;
            } else {
                break;
            }
        }
    }
    resStart[outidx++] = b;
}

__kernel void mergepack(float *orig, float *result, int *finalStartAddr, int *constStartAddr, int *nullElems) {
    int idx = get_group_id(0) * get_local_size(0) + get_local_id(0);
    int division = get_group_id(1);

    if (division >= DIVISIONS) return;

    int start = finalStartAddr[division];
    int end = finalStartAddr[division + 1];

    if (start + idx >= end) return;

    int srcIdx = constStartAddr[division] * 4 + nullElems[division] + idx;
    result[start + idx] = orig[srcIdx];
}
